const base = (env.get("PHAB_API_BASE") || "http://localhost:3000/api").replace(/\/+$/, "");
const secret = env.get("PHAB_TG_WEBHOOK_SECRET") || "";

const raw = (msg.originalMessage && typeof msg.originalMessage === "object")
  ? msg.originalMessage
  : ((msg.payload && typeof msg.payload === "object") ? msg.payload : {});

let update = raw;

if (!raw.message && !raw.callback_query) {
  const looksLikeCallback = raw && raw.from && raw.data !== undefined && (raw.message || raw.id);
  const looksLikeMessage = raw && raw.chat && (raw.text !== undefined || raw.caption !== undefined || raw.contact !== undefined || raw.reply_to_message !== undefined || raw.message_id !== undefined);

  if (looksLikeCallback) {
    update = { callback_query: raw };
  } else if (looksLikeMessage) {
    update = { message: raw };
  } else if (msg.payload && typeof msg.payload === "object" && (msg.payload.chatId !== undefined || msg.payload.content !== undefined)) {
    const chatIdRaw = msg.payload.chatId;
    const chatId = Number(chatIdRaw);
    const text = typeof msg.payload.content === "string" ? msg.payload.content : undefined;

    update = {
      message: {
        chat: { id: Number.isFinite(chatId) ? chatId : chatIdRaw, type: "private" },
        text
      }
    };
  }
}

msg.method = "POST";
msg.url = `${base}/integrations/telegram/webhook`;
msg.headers = { "Content-Type": "application/json" };
if (secret) {
  msg.headers["x-telegram-bot-api-secret-token"] = secret;
}
msg.payload = update;

return msg;

const code = Number(msg.statusCode || 0);
if (code < 200 || code >= 300) {
  node.warn(`PHAB webhook response status: ${code || "n/a"}`);
}
return null;
